function App() {
  return (
    <SidebarProvider>
      <Sidebar>
        <Sidebar.Header>
          <Logo />
          <span>Acme App</span>
          <Sidebar.CollapseToggle />
        </Sidebar.Header>
        {/* sidebar nav */}
      </Sidebar>
      <MainContent />
    </SidebarProvider>
  );
}

function MainContent() {
  const { toggleSidebar, state } = useSidebar();
  return (
    <main>
      <p>State: {state}</p>
      <button onClick={toggleSidebar}>Toggle</button>
    </main>
  );
}

